pragma solidity ^0.8.20;

contract Airdrop {
    mapping(address => uint256) public credits;

    // BAD: msg.value read inside the loop credits the single payment
    // once per recipient:
    // for (uint256 i = 0; i < recipients.length; i++) {
    //     credits[recipients[i]] += msg.value; // paid once, counted N times
    // }

    function distribute(address[] calldata recipients, uint256 amount) external payable {
        // Read and validate msg.value ONCE, before the loop, and
        // require it to cover the exact total being distributed:
        require(recipients.length > 0, "no recipients");
        require(msg.value == amount * recipients.length, "wrong total sent");

        for (uint256 i = 0; i < recipients.length; i++) {
            credits[recipients[i]] += amount; // per iteration share, not msg.value
        }
    }
}
